  1→/**
  2→ * Shared constants, data-access helpers, text-extraction utilities, and dedup.
  3→ * Port of scripts/_transcript_common.py
  4→ */
  5→
  6→import { createHash } from 'node:crypto'
  7→import { readFileSync, existsSync } from 'node:fs'
  8→
  9→import type { TranscriptMessage, TranscriptToolEvent } from '@openmnemo/types'
 10→
 11→// ---------------------------------------------------------------------------
 12→// Constants
 13→// ---------------------------------------------------------------------------
 14→
 15→export const CLIENTS: ReadonlySet<string> = new Set(['codex', 'claude', 'gemini', 'doubao'])
 16→export const TEXT_BLOCK_TYPES: ReadonlySet<string> = new Set(['input_text', 'output_text', 'text'])
 17→export const SKIP_BLOCK_TYPES: ReadonlySet<string> = new Set(['thinking', 'reasoning'])
 18→export const TOOL_USE_TYPES: ReadonlySet<string> = new Set(['tool_use'])
 19→export const TOOL_RESULT_TYPES: ReadonlySet<string> = new Set(['tool_result'])
 20→
 21→const ALL_SKIP_TYPES: ReadonlySet<string> = new Set([
 22→  ...SKIP_BLOCK_TYPES, ...TOOL_USE_TYPES, ...TOOL_RESULT_TYPES,
 23→])
 24→
 25→// ---------------------------------------------------------------------------
 26→// Generic utilities
 27→// ---------------------------------------------------------------------------
 28→
 29→export function slugify(value: string, fallback = 'session'): string {
 30→  const asciiValue = value.replace(/[^\x00-\x7F]/g, '').toLowerCase()
 31→  const slug = asciiValue.replace(/[^a-z0-9._-]+/g, '-').replace(/^[-._]+|[-._]+$/g, '')
 32→  return slug || fallback
 33→}
 34→
 35→export function sha256File(filePath: string): string {
 36→  const data = readFileSync(filePath)
 37→  return createHash('sha256').update(data).digest('hex')
 38→}
 39→
 40→export function contentHash(text: string): string {
 41→  return createHash('sha256').update(text, 'utf8').digest('hex').slice(0, 16)
 42→}
 43→
 44→export function normalizeTimestamp(value: unknown, fallback?: string | null): string {
 45→  if (typeof value === 'number') {
 46→    // Always treat as Unix seconds (matching Python's datetime.fromtimestamp)
 47→    const d = new Date(value * 1000)
 48→    return formatUtcIso(d)
 49→  }
 50→
 51→  if (value instanceof Date) {
 52→    return formatUtcIso(value)
 53→  }
 54→
 55→  if (typeof value === 'string') {
 56→    const text = value.trim()
 57→    if (!text) {
 58→      return fallback ?? normalizeTimestamp(new Date())
 59→    }
 60→    const parsed = parseIsoTimestamp(text)
 61→    if (parsed !== null) {
 62→      return formatUtcIso(parsed)
 63→    }
 64→    return text
 65→  }
 66→
 67→  return fallback ?? normalizeTimestamp(new Date())
 68→}
 69→
 70→export function earliestTimestamp(current: string, candidate: unknown): string {
 71→  const normalized = normalizeTimestamp(candidate, current)
 72→  const currentDt = parseIsoTimestamp(current)
 73→  const normalizedDt = parseIsoTimestamp(normalized)
 74→  if (currentDt !== null && normalizedDt !== null) {
 75→    return normalizedDt < currentDt ? normalized : current
 76→  }
 77→  if (normalizedDt !== null) {
 78→    return normalized
 79→  }
 80→  return current || normalized
 81→}
 82→
 83→export function parseIsoTimestamp(value: string): Date | null {
 84→  if (!value) return null
 85→  let candidate = value
 86→  if (candidate.endsWith('Z')) {
 87→    candidate = candidate.slice(0, -1) + '+00:00'
 88→  } else if (!/[+-]\d{2}:\d{2}$/.test(candidate) && !/[+-]\d{4}$/.test(candidate)) {
 89→    // No timezone offset — treat as UTC (matching Python behavior)
 90→    candidate = candidate + '+00:00'
 91→  }
 92→  const d = new Date(candidate)
 93→  if (isNaN(d.getTime())) return null
 94→  return d
 95→}
 96→
 97→export function timestampPartition(timestamp: string): [string, string] {
 98→  const d = parseIsoTimestamp(timestamp)
 99→  if (d === null) return ['unknown', 'unknown']
100→  const year = d.getUTCFullYear().toString()
101→  const month = (d.getUTCMonth() + 1).toString().padStart(2, '0')
102→  return [year, month]
103→}
104→
105→export function joinParagraphs(parts: Iterable<string>): string {
106→  const cleaned: string[] = []
107→  for (const part of parts) {
108→    const trimmed = String(part).trim()
109→    if (trimmed) cleaned.push(trimmed)
110→  }
111→  return cleaned.join('\n\n')
112→}
113→
114→export function summarizeValue(value: unknown, limit = 180): string {
115→  if (value === null || value === undefined) return 'none'
116→  if (typeof value === 'string') {
117→    const text = value.replace(/\s+/g, ' ').trim()
118→    return truncate(text, limit)
119→  }
120→  let text: string
121→  try {
122→    text = JSON.stringify(sortKeysDeep(value))
123→  } catch {
124→    text = String(value)
125→  }
126→  text = text.replace(/\s+/g, ' ').trim()
127→  return truncate(text, limit)
128→}
129→
130→export function truncate(text: string, limit: number): string {
131→  return text.length <= limit ? text : text.slice(0, limit - 3) + '...'
132→}
133→
134→export function yamlEscape(value: string): string {
135→  const escaped = value.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, '\\n')
136→  return `"${escaped}"`
137→}
138→
139→// ---------------------------------------------------------------------------
140→// Data access helpers
141→// ---------------------------------------------------------------------------
142→
143→export function ensureDict(value: unknown): Record<string, unknown> {
144→  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
145→    return value as Record<string, unknown>
146→  }
147→  return {}
148→}
149→
150→export function ensureList(value: unknown): unknown[] {
151→  return Array.isArray(value) ? value : []
152→}
153→
154→export function getNested(payload: Record<string, unknown>, ...keys: string[]): unknown {
155→  let current: unknown = payload
156→  for (const key of keys) {
157→    if (current === null || typeof current !== 'object' || Array.isArray(current)) {
158→      return null
159→    }
160→    current = (current as Record<string, unknown>)[key]
161→  }
162→  return current ?? null
163→}
164→
165→export function loadJsonl(filePath: string): Record<string, unknown>[] {
166→  let content: string
167→  try {
168→    content = readFileSync(filePath, 'utf-8')
169→  } catch {
170→    return []
171→  }
172→  const records: Record<string, unknown>[] = []
173→  for (const line of content.split('\n')) {
174→    const trimmed = line.trim()
175→    if (!trimmed) continue
176→    try {
177→      records.push(JSON.parse(trimmed) as Record<string, unknown>)
178→    } catch {
179→      continue
180→    }
181→  }
182→  return records
183→}
184→
185→export function loadJson(filePath: string): Record<string, unknown> | null {
186→  if (!existsSync(filePath)) return null
187→  try {
188→    const text = readFileSync(filePath, 'utf-8')
189→    return JSON.parse(text) as Record<string, unknown>
190→  } catch {
191→    return null
192→  }
193→}
194→
195→// ---------------------------------------------------------------------------
196→// Text extraction helpers
197→// ---------------------------------------------------------------------------
198→
199→export function extractTextBlocks(blocks: unknown): string {
200→  const parts: string[] = []
201→
202→  for (const block of ensureList(blocks)) {
203→    if (typeof block === 'string') {
204→      const text = block.trim()
205→      if (text) parts.push(text)
206→      continue
207→    }
208→    if (block === null || typeof block !== 'object' || Array.isArray(block)) continue
209→
210→    const rec = block as Record<string, unknown>
211→    const blockType = String(rec['type'] ?? '').toLowerCase()
212→    if (ALL_SKIP_TYPES.has(blockType)) continue
213→    if (TEXT_BLOCK_TYPES.has(blockType)) {
214→      const text = String(rec['text'] ?? '').trim()
215→      if (text) parts.push(text)
216→      continue
217→    }
218→    const fallbackText = extractSimpleText(block)
219→    if (fallbackText) parts.push(fallbackText)
220→  }
221→  return joinParagraphs(parts)
222→}
223→
224→export function extractSimpleText(value: unknown): string {
225→  if (typeof value === 'string') return value.trim()
226→  if (Array.isArray(value)) {
227→    return joinParagraphs(value.map(item => extractSimpleText(item)))
228→  }
229→  if (value !== null && typeof value === 'object') {
230→    const rec = value as Record<string, unknown>
231→    for (const key of ['text', 'content', 'value']) {
232→      if (key in rec && typeof rec[key] === 'string') {
233→        return (rec[key] as string).trim()
234→      }
235→    }
236→    return ''
237→  }
238→  return ''
239→}
240→
241→export function extractGeminiText(node: Record<string, unknown>): string {
242→  const parts: string[] = []
243→  for (const key of ['parts', 'content', 'text', 'message']) {
244→    parts.push(...extractGeminiParts(node[key]))
245→  }
246→  return joinParagraphs(parts)
247→}
248→
249→export function extractGeminiParts(value: unknown): string[] {
250→  if (typeof value === 'string') {
251→    const text = value.trim()
252→    return text ? [text] : []
253→  }
254→  if (Array.isArray(value)) {
255→    const parts: string[] = []
256→    for (const item of value) {
257→      parts.push(...extractGeminiParts(item))
258→    }
259→    return parts
260→  }
261→  if (value !== null && typeof value === 'object') {
262→    const rec = value as Record<string, unknown>
263→    const blockType = String(rec['type'] ?? '').toLowerCase()
264→    if (ALL_SKIP_TYPES.has(blockType)) return []
265→    if ('text' in rec && typeof rec['text'] === 'string') {
266→      const text = (rec['text'] as string).trim()
267→      return text ? [text] : []
268→    }
269→    const parts: string[] = []
270→    for (const key of ['parts', 'content']) {
271→      if (key in rec) {
272→        parts.push(...extractGeminiParts(rec[key]))
273→      }
274→    }
275→    return parts
276→  }
277→  return []
278→}
279→
280→export function findFirstMappingWithKeys(value: unknown, keys: ReadonlySet<string>): Record<string, unknown> | null {
281→  if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
282→    const rec = value as Record<string, unknown>
283→    const recKeys = Object.keys(rec)
284→    if (recKeys.some(k => keys.has(k))) return rec
285→    for (const v of Object.values(rec)) {
286→      const result = findFirstMappingWithKeys(v, keys)
287→      if (result !== null) return result
288→    }
289→    return null
290→  }
291→  if (Array.isArray(value)) {
292→    for (const item of value) {
293→      const result = findFirstMappingWithKeys(item, keys)
294→      if (result !== null) return result
295→    }
296→  }
297→  return null
298→}
299→
300→// ---------------------------------------------------------------------------
301→// Deduplication helpers
302→// ---------------------------------------------------------------------------
303→
304→export function deduplicateMessages(messages: readonly TranscriptMessage[]): TranscriptMessage[] {
305→  const seen = new Set<string>()
306→  const result: TranscriptMessage[] = []
307→  for (const msg of messages) {
308→    const sig = `${msg.timestamp ?? ''}\0${msg.role}\0${contentHash(msg.text)}`
309→    if (!seen.has(sig)) {
310→      seen.add(sig)
311→      result.push(msg)
312→    }
313→  }
314→  return result
315→}
316→
317→export function deduplicateToolEvents(events: readonly TranscriptToolEvent[]): TranscriptToolEvent[] {
318→  const seen = new Set<string>()
319→  const result: TranscriptToolEvent[] = []
320→  for (const evt of events) {
321→    const sig = `${evt.timestamp ?? ''}\0${contentHash(evt.summary)}`
322→    if (!seen.has(sig)) {
323→      seen.add(sig)
324→      result.push(evt)
325→    }
326→  }
327→  return result
328→}
329→
330→// ---------------------------------------------------------------------------
331→// Internal helpers
332→// ---------------------------------------------------------------------------
333→
334→function sortKeysDeep(value: unknown): unknown {
335→  if (Array.isArray(value)) return value.map(sortKeysDeep)
336→  if (value !== null && typeof value === 'object') {
337→    const sorted: Record<string, unknown> = {}
338→    for (const key of Object.keys(value as Record<string, unknown>).sort()) {
339→      sorted[key] = sortKeysDeep((value as Record<string, unknown>)[key])
340→    }
341→    return sorted
342→  }
343→  return value
344→}
345→
346→function formatUtcIso(d: Date): string {
347→  const year = d.getUTCFullYear()
348→  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
349→  const day = String(d.getUTCDate()).padStart(2, '0')
350→  const hours = String(d.getUTCHours()).padStart(2, '0')
351→  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
352→  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
353→  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
354→}
